var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"찾았다, 쥐새끼들.","JPN":"見つけた、ネズミども。","ENG":"I found you. You little rats.","TWN":"哟，老鼠們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?!","JPN":"な、なに！？","ENG":"W-what?","TWN":"什、什麼！？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......홀로그램 통신장치로군.","JPN":"……ホログラムの通信装置だな。","ENG":"...It's a hologram communication device.","TWN":"……是全息影像通信裝置吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 방 안에 설치되어 있었나 본데?","JPN":"この部屋の中に取り付けられているようだ。","ENG":"I guess there was one installed in this room.","TWN":"看來這個房間裡設置了這種東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"다들 쥐새끼답게 옹기종기 잘들 모여 있군.","JPN":"さすがはネズミども。仲良く1カ所に群がってるな。","ENG":"You're all gathered together like little rats.","TWN":"大家都像老鼠一樣擠在一起呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"마지막 수다는 다 떨었나?","JPN":"最後のおしゃべりは楽しめたか？","ENG":"Are you done with the last chat of your petty little lives?","TWN":"是因為這是最後一次聊天，所以在瑟瑟發抖了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"괜찮으면 슬슬 쥐약을 살포하려고 하는데 말이지.","JPN":"よければ、そろそろネズミ駆除剤を散布しようと思うのだが。","ENG":"We're about to spray the rat poison if you're ready.","TWN":"你們想要的話，要不要我撒點老鼠藥啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......누구야, 저 노출광은?","JPN":"……誰、あの露出魔は？","ENG":"Who's the stripper?","TWN":"……誰啊！這個暴露狂！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"나도 직접 보는 건 처음이지만...... 사진으로 본 기억이 있군.","JPN":"俺もリアルで見るのは初めてだが……写真で見た覚えがあるな。","ENG":"It's my first time seeing her in person... But I've seen her picture before.","TWN":"雖然我是第一次親眼看到……但我記得我在照片上看過妳！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......코드명 리플레이서 나이트.","JPN":"……コード名、リプレイサー・ナイト。","ENG":"Code Name: Replacer Knight.","TWN":"代碼名：克隆·騎士。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"현재 37개국에서 지명 수배된 1급 테러리스트다.","JPN":"現在、37カ国から指名手配を受けている第1級テロリストだ。","ENG":"She's a Class 1 terrorist on the wanted list in 37 countries.","TWN":"現在是37個國家通緝的一級恐怖份子。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하! 나도 꽤나 유명인사가 된 모양이네.","JPN":"ハハハ！　アタシもすっかり有名人だね。","ENG":"Haha! I guess I've gotten pretty famous!","TWN":"哈哈！那我也算是個名人了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......뻔뻔스럽군.","JPN":"……厚かましい奴め。","ENG":"More like infamous...","TWN":"……真不要臉。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이런 곳에서 얼굴을 드러낸 걸 보니, 아마 네놈이 이번 사건의 주동자인가 보지?","JPN":"ここで姿を表したということは、お前が今回の事件を主導した張本人なんだな？","ENG":"If you're talking to us, you must be the mastermind behind all of this?","TWN":"會在這裡露臉，看來妳這傢伙就是這次事件的主謀囉？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"넌 선을 넘어도 한참 넘었어.","JPN":"お前は、とっくのとうに一線を越えちまったんだ。","ENG":"You've gone too far this time.","TWN":"妳已經超過我很多的底線了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"감히 합중국의 요원을 살해하고 민간인을 공격하다니.......","JPN":"合衆国の要人を殺害しただけでなく、民間人まで攻撃するなんて……","ENG":"How dare you murder federal agents and attack innocent civilians...","TWN":"竟敢殺害合眾國的要員、還攻擊平民……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......대가를 치르게 될 거다.","JPN":"……代償を払ってもらうぞ。","ENG":"You'll pay dearly for this...","TWN":"……妳會付出代價的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하, 상황파악 못하고 잘난 척부터 하는 습관은 여전하군.","JPN":"ハハハ、状況把握もできないくせに、偉そうに出しゃばる癖は相変わらずだね。","ENG":"Haha! You haven't changed a bit. Getting all cocky when the odds are stacked against you.","TWN":"哈哈，你無法掌握情況，卻又愛擺出一副跩樣的習慣真是沒變呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그래, 무슨 대가를 어떻게 치르게 할 생각이지?","JPN":"それで？　どんな代償をどうやって払わせるんだ？","ENG":"So tell me... How exactly are you gonna make me pay for this?","TWN":"所以我說，你想讓我怎麼付出代價？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"허세 부리지 마라. 내가 여기서 한 방 먹었다고 네놈이 이긴 것 같나?","JPN":"調子に乗るな。俺がここで一発食わされたからって、お前の勝利だと思っているのか？","ENG":"You're the one who's getting cocky here. You think you already won just because you got to me once?","TWN":"別虛張聲勢了。妳以為妳在這裡擺了我一道，妳就算贏了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기에 온 건 빠르게 움직일 수 있었던 직속 기동부대원들뿐이야.","JPN":"ここにいるのは、速やかに移動可能な直属の機動部隊員だけだ。","ENG":"You only took out my special task force because they managed to get here sooner.","TWN":"剛才來到這裡的，只是可以立刻動員的直屬機動部隊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"멀지 않은 곳에 주력 타격부대가 대기 중이다.","JPN":"そう遠くない場所に主力の打撃部隊が待ち構えてる。","ENG":"The main strike unit is standing by not too far away.","TWN":"但在不遠處，我的主力部隊正在待命。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"네놈들을 상대하기 위해 특별히 고른 정예 요원들이지.","JPN":"お前らを懲らしめるために選び抜いた精鋭隊員だ。","ENG":"I've handpicked these elite agents specially to take you all down.","TWN":"他們都是為了對付妳，精挑細選的精銳部隊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"거기서 조금만 기다리라고.","JPN":"そこでちょっとだけ待ってろよ。","ENG":"So sit tight and wait for us.","TWN":"妳就給我等著。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그 친구들과 함께 널 박살내러 갈 테니까.","JPN":"隊員たちとともに、お前を始末しに行くからな。","ENG":"We're coming for you.","TWN":"我的那些朋友會狠狠修理妳一頓的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하, 정예 요원들이라.......","JPN":"ハハ、精鋭隊員か……","ENG":"Haha! Elite agents, you say?","TWN":"哈哈，精銳部隊喔……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"혹시...... 이 불쌍한 생쥐들을 말하는 건 아니겠지?","JPN":"それって……この哀れなネズミたちのことか？","ENG":"You don't mean... These poor little rats, do you?","TWN":"你該不會是說……這些可憐的小老鼠吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......무, 무슨?","JPN":"……な、なに？","ENG":"...W-what?","TWN":"……什、什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"마, 말도 안 돼!!","JPN":"そ、そんなまさか……！！","ENG":"No... This can't be!","TWN":"不、不會吧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"카운터는 아니지만 그래도 실전으로 잔뼈가 굵은 최정예 병사들인데!!","JPN":"カウンターではないが、実戦経歴豊富な最精鋭の兵士たちなのに！！","ENG":"They're no Counters, but they're still seasoned veterans!","TWN":"雖然不是制裁者，但他們是實戰中的最精銳士兵啊！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"설마 전멸했다고......? 겨우 한 명에게?","JPN":"まさか全滅だと……？　たった1人にか？","ENG":"There's no way... you could take them all down by yourself!","TWN":"該不會全滅了吧……被妳一個人？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"평가하자면 별 다섯 개 만점에 두 개 정도야. 다음번엔 분발하라고.","JPN":"評価をつけるとしたら星5満点中、星2つくらいだな。　もうちょっと奮発してよね。","ENG":"I'd give them 2 out of 5 stars. Better luck next time!","TWN":"嗯，如果要我評價的話，滿分五顆星他們只有兩顆星。你下次要加油一點喔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"......뭐, 너희들에게 다음번이 있을지는 모르겠지만 말이지.","JPN":"……まあ、てめえらに次回があるかはわからないけどな。","ENG":"Then again... I guess you're not going to get another chance.","TWN":"……不過，你們還有沒有下次都不知道呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하하!","JPN":"ハハハ！","ENG":"Hahaha!","TWN":"哈哈哈！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이...... 개자식!","JPN":"この……クソ野郎め！","ENG":"Why you little... bit-","TWN":"妳這……傢伙！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......이봐, 당신!","JPN":"……ちょっと、あんたね！","ENG":"Hey!","TWN":"……喂，妳！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"응? 넌 또 뭐야?","JPN":"うん？　てめえは誰だ？","ENG":"Huh? And you are?","TWN":"嗯？妳又是誰？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"어이, 저 꼬마는 뭐지? 처음 보는 얼굴인데?","JPN":"おい、あのガキは誰だ？　見た事ない奴だが。","ENG":"Who's that little kid? I've never seen her before.","TWN":"喂，這個小鬼是誰啊？看起來像個生面孔的樣子？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......도시에서 탈주한 카운터 용병들입니다.</color>","JPN":"<color=#ffd34c>……都市から脱走したカウンター傭兵です。</color>","ENG":"<color=#ffd34c>...They're the Counter mercenaries who escaped the city.</color>","TWN":"<color=#ffd34c>……這些都是從城市裡逃出來的制裁者傭兵。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>저희 부대를 기습하고 침식 억제기를 파괴한 것도 바로 저 녀석들입니다.</color>","JPN":"<color=#ffd34c>味方の部隊を襲って侵食抑制装置を破壊したのも、ズバリあいつらです。</color>","ENG":"<color=#ffd34c>They were the ones who attacked our troops and destroyed the Inhibitor.</color>","TWN":"<color=#ffd34c>突襲我們部隊的人，破壞侵蝕抑制器的人也是他們。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아마도 작전 목표인 CIA 요원과 같은 편으로 추정됩니다.</color>","JPN":"<color=#ffd34c>おそらく作戦目標のCIA要員の味方だと見られます。</color>","ENG":"<color=#ffd34c>They are most likely with the target CIA agent.</color>","TWN":"<color=#ffd34c>推測是作戰目標CIA要員的同夥。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"아, 그래? 쥐새끼에게 들러붙은 버러지 같은 거로군.","JPN":"そうか、ネズミにくっついた虫けらみたいなもんだな。","ENG":"Oh, is that so? So they're like little fleas on a rat.","TWN":"啊，是嗎？那就是附在老鼠身上的蟲子呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......대체 이런 짓을 하는 이유가 뭐지?","JPN":"……いったいなぜ、こんなことをするの？","ENG":"...Why are you doing this?","TWN":"……妳為什麼要做出這種事？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"이유? 이유라......","JPN":"なぜ？　なぜか……","ENG":"Why? Hmm...","TWN":"理由，理由的話……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 우리도 나름대로 이유가 있긴 한데......","JPN":"まあ、アタシにもそれなりの理由はあんだけどよ……","ENG":"We do have a reason for all this...","TWN":"嗯，我們不也有各自的理由嗎……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"곧 죽을 놈들에게 가르쳐 줄 필요는 없지 않겠어?","JPN":"もうじきあの世行きの奴らに教えてもしょうがないよな？","ENG":"But what's the point of explaining it to people who will soon be dead?","TWN":"又何必去告訴你們這些快死的人呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 그게 무슨......?","JPN":"えっ？　それはどういう……？","ENG":"Huh? What do you mean?","TWN":"什麼？妳說什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이, 이봐! 뭔가 잔뜩 몰려오고 있어!","JPN":"お、おい！　何かがわんさか押し寄せているぜ！","ENG":"Hey! Something's headed our way!","TWN":"喂，等一下！好像有很多東西聚集到這裡來了耶。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이번엔 괴물들만 있는 게 아니야! 중화기도 잔뜩 끌고 오는데?","JPN":"化け物だけじゃねえ！　重火器使いも多い！","ENG":"And they're not just monsters this time! They're carrying heavy firearms!","TWN":"這次似乎不只有怪物，還有很多重型武器啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"어, 어떻게 하지? 말 좀 해 봐, 메이슨!","JPN":"ど、どうする？　何か言えよ、メイソン！","ENG":"What do we do? What's the plan, Mason?","TWN":"我、我們該怎麼辦？你說話啊，梅森！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하하핫!","JPN":"ははははっ！","ENG":"Hahahaha!","TWN":"哈哈哈哈。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그럼 마음껏 발버둥 쳐 보라고!","JPN":"せいぜい、あがいて見せろや！","ENG":"Go give it your best shot!","TWN":"你們就盡情地掙扎吧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"버러지들아.","JPN":"この虫けらどもめ。","ENG":"Little rats.","TWN":"蟲子們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어, 어쩌죠. 아저씨?","JPN":"ど、どうします？　おじさん。","ENG":"W-what should we do? Mister?","TWN":"怎、怎麼辦啊，大叔？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......어쩌긴.","JPN":"……どうにもこうにも。","ENG":"That's simple...","TWN":"……怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"적들을 앞에 두고 용병이 할일은 하나뿐이지.","JPN":"敵を前にした傭兵のすべきことは決まってるさ。","ENG":"There's only one thing a mercenary can do when he's faced with an enemy.","TWN":"面對敵人，我們傭兵能做的，就只有一件事。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......어떻게든 살아남는다!","JPN":"……なんとしても生き残るんだ！","ENG":"...Do whatever it takes to survive!","TWN":"……那就是不管怎麼樣，都要活下去！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};